import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as d,c as e,e as r}from"./app-9eba4673.js";const a={},h=r('<h1 id="入世手记" tabindex="-1"><a class="header-anchor" href="#入世手记" aria-hidden="true">#</a> 入世手记</h1><h2 id="五险一金" tabindex="-1"><a class="header-anchor" href="#五险一金" aria-hidden="true">#</a> 五险一金</h2><p>五险一金由单位和个人一起缴纳。每个人都有一个个人账户和统筹账户，个人账户存的是自己的钱，统筹账户是存的帮别人的钱。比如年轻时交的养老保险一部分存到个人账户一部分存到统筹账户。等交满年限之后老了就会从个人账户中每个月打钱给你。如果没交满年限不想交了也可以把个人账户中的钱全部取出来。个人账户的钱死了之后可以继承给家人。</p><table><thead><tr><th>名称</th><th>个人</th><th>单位</th><th>用途</th></tr></thead><tbody><tr><td>养老保险</td><td>8%</td><td>16%</td><td>老了领取养老金(需要交满20年，不怕断缴)</td></tr><tr><td>医疗保险</td><td>2%</td><td>8%</td><td>看病住院买药可以报销钱(交满20-25年之后永久享受医保，不要断缴)</td></tr><tr><td>失业保险</td><td>0.5%</td><td>0.5%</td><td>失业了能领钱(需要累计缴满一年，并且是被公司裁才能领，最多领两年)</td></tr><tr><td>工伤保险</td><td>0</td><td>0.2-1.4%</td><td>工作受伤能赔钱</td></tr><tr><td>生育保险</td><td>0</td><td>5-12%</td><td>生孩子能领部分钱</td></tr><tr><td>住房公积金</td><td>5-12%</td><td>5-12%</td><td>属于个人财产，只是在另一个地方存了起来</td></tr></tbody></table><p>表中的个人比例是按照自己的工资 × 比例就是自己这个月需要缴纳的钱。比如工资是6000，养老保险的个人比例是8%，那么这个月的养老保险你需要交6000 × 8% = 480。如果显示少于480则公司不是按照你的工资交的，有可能是当地最低缴费基数交的。交的越少则社保待遇越差。五险一金都是要缴纳的，不然违法。只要是签署了劳动合同不给缴纳的都违法。所以试用期也是需要缴纳五险一金的。不给缴纳的可以拨打12333投诉。</p><h2 id="工资组成" tabindex="-1"><a class="header-anchor" href="#工资组成" aria-hidden="true">#</a> 工资组成</h2><p>工资用来交税(5000以下不用交税)和缴纳五险一金之后剩下的钱才是自己实际每个月能领到的钱。</p>',7),c=[h];function o(n,i){return d(),e("div",null,c)}const l=t(a,[["render",o],["__file","入世手记.html.vue"]]);export{l as default};
